wsc:message.wsc:body:
#[%dw 2.0
output application/xml
ns tns http://www.example.org/ControlPresencia/
---
{
  tns#controlEmpleadosSala: {
    tns#WSKey: "SOAP-DEV-KEY-001",
    tns#in: (attributes.queryParams.codigoSala default "100") as Number
  }
}]

ee:message.ee:set-payload:
%dw 2.0 output application/json
var empleados = payload.body.controlEmpleadosSalaResponse.out.*empleados var errorSoap = payload.body.controlEmpleadosSalaResponse.error
--- { data: empleados map (emp) -> { nif: emp.nif as String, nombreApellidos: emp.nombreApellidos as String, email: emp.email as String }, total: sizeOf(empleados), error: if (errorSoap == null or errorSoap == "") null else errorSoap as String }
